{
  "schema_name": "eywa_node_response",
  "schema_version": "v1",
  "orchestration_decision": "delegate",
  "decision_notes": "The problem requires a logical chain analysis of 45 rules to determine if a specific state (butterfly revealing a secret to the fish) is reachable or provable. This is best split into rule extraction/mapping and logical path tracing.",
  "helpers": [
    {
      "label": "rule_mapper",
      "instructions": "Analyze the provided 45 rules of the board game. Identify and list all rules that involve the butterfly, the fish, or the concept of revealing secrets. Map out the causal relationships or conditional triggers between these entities to create a directed graph of possible interactions."
    },
    {
      "label": "logic_tracer",
      "instructions": "Using the rule map provided, attempt to construct a logical chain of events that leads from the starting state to the specific outcome: the butterfly reveals a secret to the fish. Determine if this outcome is a necessary consequence, a possible consequence, or if there is insufficient information to conclude whether it happens or not."
    }
  ],
  "synthesis_brief": "The parent agent will take the rule map and the logical trace to determine if the conclusion is definitively true, definitively false, or unknown. If the chain cannot be completed or if the rules do not provide enough information to bridge the gap between the butterfly and the fish, the final answer must be 'unknown' as per the grading target."
}

